use actix_web::{web, HttpResponse, Result, HttpRequest};
use actix_files::NamedFile;
use std::path::{PathBuf, Path};
use sanitize_filename;

const UPLOADS_DIR: &str = "./uploads";

pub async fn serve_file(req: HttpRequest, filename: web::Path<String>) -> Result<NamedFile> {
    let sanitized_filename = sanitize_filename::sanitize(&filename.into_inner());
    
    if sanitized_filename.is_empty() {
        return Err(actix_web::error::ErrorBadRequest("Invalid filename"));
    }
    
    let uploads_path = Path::new(UPLOADS_DIR).canonicalize()
        .map_err(|_| actix_web::error::ErrorInternalServerError("Upload directory not found"))?;
    
    let mut file_path = PathBuf::from(&uploads_path);
    file_path.push(&sanitized_filename);
    
    let file_path = file_path.canonicalize()
        .map_err(|_| actix_web::error::ErrorNotFound("File not found"))?;
    
    if !file_path.starts_with(&uploads_path) {
        return Err(actix_web::error::ErrorForbidden("Access denied"));
    }
    
    if !file_path.is_file() {
        return Err(actix_web::error::ErrorNotFound("File not found"));
    }
    
    Ok(NamedFile::open(file_path)?)
}

pub fn configure_routes(cfg: &mut web::ServiceConfig) {
    cfg.service(
        web::resource("/files/{filename}")
            .route(web::get().to(serve_file))
    );
}

